#include "bsp_i2c.h"

/* ----------------------------------------------------------------------
 * External HAL handles generated by CubeMX.
 * Make sure these names match your project.
 * -------------------------------------------------------------------- */
extern I2C_HandleTypeDef hi2c4;

/* ----------------------------------------------------------------------
 * Internal bus structure.
 * -------------------------------------------------------------------- */
typedef enum
{
    BSP_I2C_XFER_IDLE = 0,
    BSP_I2C_XFER_BUSY
} bsp_i2c_xfer_state_t;

typedef enum
{
    BSP_I2C_XFER_TYPE_NONE = 0,
    BSP_I2C_XFER_TYPE_TX,
    BSP_I2C_XFER_TYPE_RX,
    BSP_I2C_XFER_TYPE_MEM_TX,
    BSP_I2C_XFER_TYPE_MEM_RX,
} bsp_i2c_xfer_type_t;

typedef struct bsp_i2c_bus
{
    I2C_HandleTypeDef       *hi2c;

    volatile bsp_i2c_xfer_state_t state;
    volatile bsp_i2c_xfer_type_t  xfer_type;

    bsp_i2c_device_t        *current_dev;
    bsp_i2c_callback_t       current_cb;
    void                    *current_cb_ctx;

    /* For MEM transfers we keep register info here */
    uint16_t                 mem_addr;
    uint16_t                 mem_addr_size;
} bsp_i2c_bus_t;

/* ----------------------------------------------------------------------
 * Global bus table.
 * Later you can append I2C1, I2C2, ... here.
 * -------------------------------------------------------------------- */
static bsp_i2c_bus_t s_i2c_buses[BSP_I2C_BUS_MAX] = {
    [BSP_I2C_BUS_4] =
    {
        .hi2c         = &hi2c4,
        .state        = BSP_I2C_XFER_IDLE,
        .xfer_type    = BSP_I2C_XFER_TYPE_NONE,
        .current_dev  = NULL,
        .current_cb   = NULL,
        .current_cb_ctx = NULL,
        .mem_addr     = 0,
        .mem_addr_size = 0,
    }
};

/* ----------------------------------------------------------------------
 * Local helpers.
 * -------------------------------------------------------------------- */

/**
 * @brief Get bus pointer by ID.
 */
static bsp_i2c_bus_t *bsp_i2c_get_bus_by_id(bsp_i2c_bus_id_t id)
{
    if (id >= BSP_I2C_BUS_MAX)
    {
        return NULL;
    }
    return &s_i2c_buses[id];
}

/**
 * @brief Get bus pointer by HAL I2C handle.
 *
 * Used in HAL callbacks to find which bus triggered the IRQ.
 */
static bsp_i2c_bus_t *bsp_i2c_get_bus_by_handle(I2C_HandleTypeDef *hi2c)
{
    for (int i = 0; i < BSP_I2C_BUS_MAX; ++i)
    {
        if (s_i2c_buses[i].hi2c == hi2c)
        {
            return &s_i2c_buses[i];
        }
    }
    return NULL;
}

/* ----------------------------------------------------------------------
 * Public APIs.
 * -------------------------------------------------------------------- */

void bsp_i2c_init(void)
{
    /*
     * No special runtime configuration for now.
     * Just reset states. HAL I2C init (MX_I2C4_Init) must be called before.
     */
    for (int i = 0; i < BSP_I2C_BUS_MAX; ++i)
    {
        s_i2c_buses[i].state = BSP_I2C_XFER_IDLE;
        s_i2c_buses[i].xfer_type = BSP_I2C_XFER_TYPE_NONE;
        s_i2c_buses[i].current_dev = NULL;
        s_i2c_buses[i].current_cb = NULL;
        s_i2c_buses[i].current_cb_ctx = NULL;
        s_i2c_buses[i].mem_addr = 0;
        s_i2c_buses[i].mem_addr_size = 0;
    }
}

bsp_i2c_status_t bsp_i2c_device_init(bsp_i2c_device_t *dev,
                                     bsp_i2c_bus_id_t bus_id,
                                     uint16_t addr_7bit)
{
    if (dev == NULL)
    {
        return BSP_I2C_INVALID_PARAM;
    }

    bsp_i2c_bus_t *bus = bsp_i2c_get_bus_by_id(bus_id);
    if (bus == NULL || bus->hi2c == NULL)
    {
        return BSP_I2C_ERROR;
    }

    dev->bus = bus;
    dev->addr_7bit = addr_7bit & 0x7F;

    /* Default config, can be overridden by upper layer if needed */
    dev->max_speed_hz = 0;   /* 0 = use HAL config */
    dev->flags = 0;          /* Reserved for future use */

    return BSP_I2C_OK;
}

/**
 * @brief Non-blocking master transmit using DMA/IT (here using HAL DMA if enabled, else IT).
 */
bsp_i2c_status_t bsp_i2c_master_transmit(bsp_i2c_device_t *dev,
                                         const uint8_t *tx_buf,
                                         size_t len,
                                         bsp_i2c_callback_t cb,
                                         void *user_ctx)
{
    if (dev == NULL || dev->bus == NULL || tx_buf == NULL || len == 0U)
    {
        return BSP_I2C_INVALID_PARAM;
    }

    bsp_i2c_bus_t *bus = dev->bus;

    if (bus->state == BSP_I2C_XFER_BUSY)
    {
        return BSP_I2C_BUSY;
    }

    bus->state = BSP_I2C_XFER_BUSY;
    bus->xfer_type = BSP_I2C_XFER_TYPE_TX;
    bus->current_dev = dev;
    bus->current_cb = cb;
    bus->current_cb_ctx = user_ctx;

    HAL_StatusTypeDef hal_ret;

#if (USE_HAL_I2C_REGISTER_CALLBACKS == 1) || defined(I2C4) /* Just a placeholder branch */
    /* Use DMA if enabled in CubeMX, otherwise IT. You can tweak this as needed. */
    hal_ret = HAL_I2C_Master_Transmit_DMA(bus->hi2c,
                                          (uint16_t)(dev->addr_7bit << 1),
                                          (uint8_t *)tx_buf,
                                          (uint16_t)len);
#else
    hal_ret = HAL_I2C_Master_Transmit_IT(bus->hi2c,
                                         (uint16_t)(dev->addr_7bit << 1),
                                         (uint8_t *)tx_buf,
                                         (uint16_t)len);
#endif

    if (hal_ret != HAL_OK)
    {
        bus->state = BSP_I2C_XFER_IDLE;
        bus->xfer_type = BSP_I2C_XFER_TYPE_NONE;
        bus->current_dev = NULL;
        bus->current_cb = NULL;
        bus->current_cb_ctx = NULL;
        return BSP_I2C_ERROR;
    }

    return BSP_I2C_OK;
}

