/**
 * @brief Blocking wrapper for non-blocking APIs.
 */
bsp_i2c_status_t bsp_i2c_wait_complete(bsp_i2c_device_t *dev,
                                       uint32_t timeout_ms)
{
    if (dev == NULL || dev->bus == NULL)
    {
        return BSP_I2C_INVALID_PARAM;
    }

    bsp_i2c_bus_t *bus = dev->bus;
    uint32_t start = HAL_GetTick();

    while (bus->state == BSP_I2C_XFER_BUSY)
    {
        if ((HAL_GetTick() - start) > timeout_ms)
        {
            (void)HAL_I2C_Master_Abort_IT(bus->hi2c, (uint16_t)(dev->addr_7bit << 1));
            bus->state = BSP_I2C_XFER_IDLE;
            bus->xfer_type = BSP_I2C_XFER_TYPE_NONE;
            bus->current_dev = NULL;
            bus->current_cb = NULL;
            bus->current_cb_ctx = NULL;
            return BSP_I2C_BUSY;
        }
    }

    return BSP_I2C_OK;
}

bsp_i2c_status_t bsp_i2c_is_bus_busy(const bsp_i2c_device_t *dev)
{
    if (dev == NULL || dev->bus == NULL)
    {
        return BSP_I2C_INVALID_PARAM;
    }

    return (dev->bus->state == BSP_I2C_XFER_BUSY) ? BSP_I2C_BUSY : BSP_I2C_OK;
}

/* ----------------------------------------------------------------------
 * HAL callbacks.
 *
 * These callbacks are called from HAL I2C IRQ context.
 * We translate them to BSP-level logic and then call user callbacks.
 * -------------------------------------------------------------------- */

static void bsp_i2c_on_complete(I2C_HandleTypeDef *hi2c, bsp_i2c_status_t status)
{
    bsp_i2c_bus_t *bus = bsp_i2c_get_bus_by_handle(hi2c);
    if (bus == NULL)
    {
        return;
    }

    bsp_i2c_device_t *dev = bus->current_dev;
    bsp_i2c_callback_t cb = bus->current_cb;
    void *ctx = bus->current_cb_ctx;

    bus->state = BSP_I2C_XFER_IDLE;
    bus->xfer_type = BSP_I2C_XFER_TYPE_NONE;
    bus->current_dev = NULL;
    bus->current_cb = NULL;
    bus->current_cb_ctx = NULL;
    bus->mem_addr = 0;
    bus->mem_addr_size = 0;

    if (cb != NULL && dev != NULL)
    {
        cb(dev, ctx, status);
    }
}

void HAL_I2C_MasterTxCpltCallback(I2C_HandleTypeDef *hi2c)
{
    bsp_i2c_on_complete(hi2c, BSP_I2C_OK);
}

void HAL_I2C_MasterRxCpltCallback(I2C_HandleTypeDef *hi2c)
{
    bsp_i2c_on_complete(hi2c, BSP_I2C_OK);
}

void HAL_I2C_MemTxCpltCallback(I2C_HandleTypeDef *hi2c)
{
    bsp_i2c_on_complete(hi2c, BSP_I2C_OK);
}

void HAL_I2C_MemRxCpltCallback(I2C_HandleTypeDef *hi2c)
{
    bsp_i2c_on_complete(hi2c, BSP_I2C_OK);
}

void HAL_I2C_ErrorCallback(I2C_HandleTypeDef *hi2c)
{
    bsp_i2c_on_complete(hi2c, BSP_I2C_ERROR);
}